A solution





// Zeros and ones (1)
#include&lt;iostream&gt;
#include&lt;vector&gt;

using namespace std;

void write (const vector&lt;bool&gt; & v){
    cout &lt;&lt; v[0];
    for (int i = 1; i &lt; v.size(); ++i)
        cout &lt;&lt; " " &lt;&lt; v[i];
    cout &lt;&lt; endl;
}

void backtrack(vector&lt;bool&gt;& sol, int k){
    if (k == sol.size()) write(sol);
    else{
        sol[k] = false;
        backtrack(sol, k+1);
        sol[k] = true;
        backtrack(sol, k+1);
    }
}

int main(){
    int n;
    cin &gt;&gt; n;
    vector&lt;bool&gt; sol(n);
    backtrack(sol, 0);
}





