// Permutations of words
#include&lt;iostream&gt;
#include&lt;vector&gt;
#include&lt;string&gt;

using namespace std;

void write (const vector&lt;int&gt; & v, const vector&lt;string&gt;& words){
    cout &lt;&lt; '(' &lt;&lt; words[v[0]];
    for (int i = 1; i &lt; v.size(); ++i)
        cout &lt;&lt; ',' &lt;&lt; words[v[i]];
    cout &lt;&lt; ')' &lt;&lt; endl;
}

void perm(vector&lt;int&gt;& sol, int k, vector&lt;bool&gt; used, const vector&lt;string&gt;& words){
    int n = sol.size();
    if (k == n) write(sol, words);
    else{
        for (int i = 0; i &lt; n; ++i){
            if (not used[i]){
                sol[k] = i;
                used[i] = true;
                perm(sol, k+1, used, words);
                used[i] = false;
            }
        }
    }
}

int main(){
    int n;
    cin &gt;&gt; n;
    vector&lt;string&gt; words(n,"");
    for (int i = 0;  i &lt; n; ++i)
        cin &gt;&gt; words[i];
    vector&lt;int&gt; sol(n,0);
    vector&lt;bool&gt; used(n, false);
    perm(sol, 0, used, words);
}





