A solution





// Consonants and vowels
#include&lt;iostream&gt;
#include&lt;vector&gt;
#include&lt;string&gt;

using namespace std;
using VVB = vector&lt;vector&lt;bool&gt;&gt;;
using VB = vector&lt;bool&gt;;

const int CONSONANTS = 0;
const int VOWELS = 1;

void backtrack(string& sol, int k, const vector&lt;string&gt;& letters, VVB& used){
    int m = sol.size();
    if (k == m) cout &lt;&lt; sol &lt;&lt; endl;
    else{
        int k2 = k%2;
        for(int i = 0; i &lt; m/2; ++i)
            if (not used[k2][i]){
                sol[k] = letters[k2][i];
                used[k2][i] = true;
                backtrack(sol, k+1, letters, used);
                used[k2][i] = false;
            }
    }
}

int main(){
    int n;
    cin &gt;&gt; n;
    vector&lt;string&gt; letters(2); 
    cin &gt;&gt; letters[CONSONANTS] &gt;&gt; letters[VOWELS];
    string sol = string(2*n, ' ');
    VVB used(2, VB(n, false));
    backtrack(sol, 0, letters, used);
}





Two coins of each kind (1) 🔶

Given a natural number \(x\) and \(n\) different coin values \(c_1 \dots c_n\), compute in how many ways it is possible to achieve change \(x\) by using each value at most twice. Here, two coins with the same value are considered different.
For example, if \(x = 4\) and the available values are \(1\) and \(2\), then there are three ways to achieve it: \(1 + 1^′ + 2\), \(1 + 1^′ + 2^′\), and also \(2 + 2^′\).
