// Topological sort
#include&lt;iostream&gt;
#include&lt;vector&gt;
#include&lt;queue&gt;

using namespace std;
using graph = vector&lt;vector&lt;int&gt;&gt;;
using VI = vector&lt;int&gt;;

VI compute_ordering(const graph& g, VI& indegree){
    int n = g.size();
    priority_queue&lt;int, vector&lt;int&gt;, greater&lt;int&gt;&gt; pq;
    for (int u =0; u &lt; n; ++u){
        if (indegree[u]==0) pq.push(u);
    }
    VI ord;
    while(not pq.empty()){
        int u = pq.top();
        pq.pop();
        ord.push_back(u);
        for (int k = 0; k &lt; g[u].size(); ++k){
            int v = g[u][k];
            --indegree[v];
            if (indegree[v]==0) pq.push(v);
        }
    }
    return ord;
}

void write(const VI& v){
    cout &lt;&lt; v[0];
    for (int i = 1; i &lt; v.size(); ++i)
        cout  &lt;&lt; ' ' &lt;&lt; v[i];
    cout &lt;&lt; endl;
}

int main(){
    int n, m;
    while(cin &gt;&gt; n &gt;&gt; m){
        graph g(n);
        VI indegree(n, 0);
        for (int i = 0; i &lt; m; ++i){
            int u, v;
            cin &gt;&gt; u &gt;&gt; v;
            g[u].push_back(v);
            ++indegree[v];
        }
    VI ord = compute_ordering(g,indegree);
    write(ord);
    }
}






