            cin &gt;&gt; map[i][j];
    int r,c;
    cin &gt;&gt; r &gt;&gt; c;
    int dist = bfs(map, r-1, c-1);
    if (dist == UNDEF) cout &lt;&lt; "no treasure can be reached" &lt;&lt; endl;
