//Modular exponentiation
#include&lt;iostream&gt;

using namespace std;

int power(int n, int k, int m){
    if (k == 0) return 1;
    int y = power(n, k/2, m);
    int res = (y*y) % m;
    if (k % 2 == 1) return (n*res) % m;// return (n*y*y) % m; is NOT OK!
    else return res;
}

int main(){
    /*
    const int M_MAX = 30000;
    const int N_MAX = 30000;
